mapper.select:
SELECT id, user_id, username, module_name, operation_type, method,
       request_url, request_param, response_result, exception_msg,
       status, cost_time, operate_ip, operate_time
FROM sys_operation_log
WHERE tenant_id = #{tenantId}

    AND username LIKE CONCAT('%', #{q.username}, '%')


    AND module_name LIKE CONCAT('%', #{q.moduleName}, '%')


    AND operation_type LIKE CONCAT('%', #{q.operationType}, '%')


    AND status = #{q.status}


    AND operate_time >= #{q.beginTime}


    AND operate_time <= #{q.endTime}

ORDER BY operate_time DESC

SELECT id, user_id, username, module_name, operation_type, method,
       request_url, request_param, response_result, exception_msg,
       status, cost_time, operate_ip, operate_time
FROM sys_operation_log
WHERE tenant_id = #{tenantId}

    AND username LIKE CONCAT('%', #{q.username}, '%')


    AND module_name LIKE CONCAT('%', #{q.moduleName}, '%')


    AND status = #{q.status}


    AND operate_time >= #{q.beginTime}


    AND operate_time <= #{q.endTime}

ORDER BY operate_time DESC
LIMIT 10000
